import React, { useEffect, useRef, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Plane,
  Hotel,
  Car,
  Ship,
  Calendar,
  Users,
  Search,
  Phone,
  ArrowLeft,
  ArrowRight,
  ChevronDown,
  DollarSign,
  Clock3,
  Shield,
  Headphones,
  Award,
  Globe,
  Heart,
  Star,
} from 'lucide-react';
import { useContact } from '../context/ContactContext';
import AirportAutocomplete from '../components/AirportAutocomplete';
import './HomeNew.css';

const dealCards = [
  {
    city: 'Washington D.C.',
    duration: '18h 10m, 1 stop',
    dates: 'Fri 6/9 • Mon 9/9',
    image: 'https://images.unsplash.com/photo-1617581629397-a72507c3de9e?w=900&h=620&fit=crop',
  },
  {
    city: 'Miami',
    duration: '19h 15m, 1 stop',
    dates: 'Thu 5/9 • Wed 11/9',
    image: 'https://images.unsplash.com/photo-1535498730771-e735b998cd64?w=900&h=620&fit=crop',
  },
  {
    city: 'New York City',
    duration: '15h 30m, 1 stop',
    dates: 'Mon 2/9 • Sun 8/9',
    image: 'https://images.unsplash.com/photo-1485738422979-f5c462d49f74?w=900&h=620&fit=crop',
  },
  {
    city: 'Los Angeles',
    duration: '17h 45m, 1 stop',
    dates: 'Tue 10/9 • Sat 14/9',
    image: 'https://images.unsplash.com/photo-1534190760961-74e8c1c5c3da?w=900&h=620&fit=crop',
  },
  {
    city: 'Chicago',
    duration: '16h 20m, 1 stop',
    dates: 'Wed 4/9 • Fri 13/9',
    image: 'https://images.unsplash.com/photo-1506744038136-46273834b3fb?w=900&h=620&fit=crop',
  },
  {
    city: 'Orlando',
    duration: '20h 5m, 1 stop',
    dates: 'Sat 7/9 • Thu 12/9',
    image: 'https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=900&h=620&fit=crop',
  },
  {
    city: 'San Francisco',
    duration: '18h 50m, 1 stop',
    dates: 'Sun 1/9 • Wed 11/9',
    image: 'https://images.unsplash.com/photo-1501594907352-04cda38ebc29?w=900&h=620&fit=crop',
  },{
    city: 'Las Vegas',
    duration: '19h 30m, 1 stop',
    dates: 'Mon 3/9 • Fri 7/9',
    image: 'https://images.unsplash.com/photo-1494526585095-c41746248156?w=900&h=620&fit=crop',
  }
];

const coreValues = [
  { icon: Award, title: 'Excellence', text: 'We strive for excellence in every aspect of our service, from booking to customer support.', tone: 'blue' },
  { icon: Users, title: 'Customer First', text: 'Our customers are at the heart of everything we do. Your satisfaction is our priority.', tone: 'green' },
  { icon: Globe, title: 'Innovation', text: 'We continuously innovate to provide the best travel booking experience possible.', tone: 'cyan' },
  { icon: Heart, title: 'Trust', text: 'We build lasting relationships based on trust, transparency, and reliability.', tone: 'pink' },
];

const whyChoose = [
  { icon: DollarSign, title: 'Best Price Guarantee', text: "We guarantee the lowest prices on domestic flights. Find a better deal? We'll match it.", tone: 'green' },
  { icon: Clock3, title: 'Instant Booking', text: 'Book your flights in seconds with our streamlined booking process. No hidden fees.', tone: 'blue' },
  { icon: Shield, title: 'Secure Payments', text: 'Your payment information is protected with bank-level security and encryption.', tone: 'yellow' },
  { icon: Headphones, title: '24/7 Support', text: 'Our customer support team is available round the clock to assist you.', tone: 'cyan' },
];

const airlines = [
  {
    name: 'Southwest',
    logo: "data:image/jpeg;base64,",
  },
  {
    name: 'Delta',
    logo: "data:image/webp;base64," ,
  },
  {
    name: 'Spirit',
    logo: 'data:image/png;base64,',
  },
  {
    name: 'United',
    logo: "data:image/webp;base64," ,
  },
  {
    name: 'Emirates',
    logo: 'data:image/webp;base64,',
  },
  {
    name: 'American',
    logo: "data:image/jpeg;base64,",
  },
];

function HomeNew() {
  const navigate = useNavigate();
  const { contactSettings } = useContact();

  const [activeTab, setActiveTab] = useState('flights');
  const [tripType, setTripType] = useState('roundtrip');
  const [showPassengers, setShowPassengers] = useState(false);
  const passengerRef = useRef(null);
  const [dealsStart, setDealsStart] = useState(0);
  const [airlineQuery, setAirlineQuery] = useState('');
  const [searchData, setSearchData] = useState({
    from: '',
    to: '',
    departDate: new Date().toISOString().split('T')[0],
    returnDate: '',
    passengers: { adults: 1, children: 0, infants: 0 },
    cabinClass: 'economy',
  });

  const phone = contactSettings.tfn || '+1-866-560-8871';
  const dialPhone = phone.replace(/[^0-9+]/g, '');

  const totalTravelers = searchData.passengers.adults + searchData.passengers.children + searchData.passengers.infants;
  const visibleDeals = [
    dealCards[dealsStart % dealCards.length],
    dealCards[(dealsStart + 1) % dealCards.length],
    dealCards[(dealsStart + 2) % dealCards.length],
    dealCards[(dealsStart + 3) % dealCards.length],
  ];
  const filteredAirlines = airlines.filter((airline) =>
    airline.name.toLowerCase().includes(airlineQuery.trim().toLowerCase())
  );

  const updatePassengers = (type, value) => {
    setSearchData((prev) => ({
      ...prev,
      passengers: {
        ...prev.passengers,
        [type]: Math.max(type === 'adults' ? 1 : 0, value),
      },
    }));
  };

  useEffect(() => {
    const closeOnOutside = (event) => {
      if (passengerRef.current && !passengerRef.current.contains(event.target)) {
        setShowPassengers(false);
      }
    };
    document.addEventListener('mousedown', closeOnOutside);
    return () => document.removeEventListener('mousedown', closeOnOutside);
  }, []);

  const handleSearch = () => {
    if (activeTab === 'flights') {
      if (!searchData.from || !searchData.to) {
        alert('Please select departure and destination cities');
        return;
      }
      if (!searchData.departDate) {
        alert('Please select departure date');
        return;
      }
      if (tripType === 'roundtrip' && !searchData.returnDate) {
        alert('Please select return date');
        return;
      }
      navigate('/flight-results', {
        state: {
          searchParams: {
            from: searchData.from,
            to: searchData.to,
            departDate: searchData.departDate,
            returnDate: searchData.returnDate,
            tripType,
            passengers: searchData.passengers,
            cabinClass: searchData.cabinClass,
          },
        },
      });
    } else if (activeTab === 'hotels') {
      navigate('/hotel-results');
    } else if (activeTab === 'cruises') {
      navigate('/cruise-results');
    } else if (activeTab === 'packages') {
      navigate('/package-results');
    }
  };

  return (
    <div className="home-aof">
      <section className="aof-hero">
        <div className="aof-hero-content">
          <h1>
            Your Perfect Deal is Just a Call Away! <span>{phone}</span> 24/7 Support!
          </h1>

          <div className="aof-service-tabs">
            <button className={`aof-service ${activeTab === 'flights' ? 'active' : ''}`} onClick={() => setActiveTab('flights')}>
              <span className="aof-service-icon"><Plane size={24} /></span>
              <span>Flights</span>
            </button>
            <button className={`aof-service ${activeTab === 'hotels' ? 'active' : ''}`} onClick={() => setActiveTab('hotels')}>
              <span className="aof-service-icon"><Hotel size={24} /></span>
              <span>Hotels</span>
            </button>
            
          </div>

          <div className="aof-trip-type">
            <label className="trip-radio">
              <input
                type="radio"
                checked={tripType === 'oneway'}
                onChange={() => setTripType('oneway')}
              />
              <span>One-way</span>
            </label>
            <label className="trip-radio">
              <input
                type="radio"
                checked={tripType === 'roundtrip'}
                onChange={() => setTripType('roundtrip')}
              />
              <span>Round-trip</span>
            </label>
          </div>

        </div>
        <div className="aof-hero-art">
          <div className="slice s1" />
          <div className="slice s2" />
          <div className="slice s3" />
        </div>
        <div className="aof-form-row">
          <div className={`aof-search-strip ${tripType === 'roundtrip' ? 'roundtrip' : 'oneway'}`}>
            <div className="aof-search-cell from-cell">
              <Plane size={18} />
              <AirportAutocomplete
                value={searchData.from}
                onChange={(value) => setSearchData({ ...searchData, from: value })}
                placeholder="From?"
              />
            </div>
            <div className="aof-search-cell to-cell">
              <Plane size={18} />
              <AirportAutocomplete
                value={searchData.to}
                onChange={(value) => setSearchData({ ...searchData, to: value })}
                placeholder="To?"
              />
            </div>
            <div className="aof-search-cell depart-cell">
              <Calendar size={18} />
              <input
                type="date"
                value={searchData.departDate}
                onChange={(e) => setSearchData({ ...searchData, departDate: e.target.value })}
                min={new Date().toISOString().split('T')[0]}
              />
            </div>
            {tripType === 'roundtrip' && (
              <div className="aof-search-cell return-cell">
                <Calendar size={18} />
                <input
                  type="date"
                  value={searchData.returnDate}
                  onChange={(e) => setSearchData({ ...searchData, returnDate: e.target.value })}
                  min={searchData.departDate || new Date().toISOString().split('T')[0]}
                />
              </div>
            )}
            <div className="aof-search-cell passengers" ref={passengerRef}>
              <button
                type="button"
                className="passenger-trigger"
                onClick={() => setShowPassengers((prev) => !prev)}
              >
                <Users size={18} />
                <span>{totalTravelers} Passenger, {searchData.cabinClass.toUpperCase()}</span>
                <ChevronDown size={16} className={showPassengers ? 'open' : ''} />
              </button>
              {showPassengers && (
                <div className="aof-passenger-dropdown" onClick={(e) => e.stopPropagation()}>
                  {['adults', 'children', 'infants'].map((k) => (
                    <div key={k} className="row">
                      <span>{k[0].toUpperCase() + k.slice(1)}</span>
                      <div>
                        <button type="button" onClick={() => updatePassengers(k, searchData.passengers[k] - 1)}>-</button>
                        <strong>{searchData.passengers[k]}</strong>
                        <button type="button" onClick={() => updatePassengers(k, searchData.passengers[k] + 1)}>+</button>
                      </div>
                    </div>
                  ))}
                  <select
                    value={searchData.cabinClass}
                    onChange={(e) => setSearchData({ ...searchData, cabinClass: e.target.value })}
                  >
                    <option value="economy">Economy</option>
                    <option value="premium_economy">Premium Economy</option>
                    <option value="business">Business</option>
                    <option value="first">First Class</option>
                  </select>
                </div>
              )}
            </div>
            <button className="aof-search-btn" onClick={handleSearch}>
              <Search size={20} />
            </button>
          </div>
        </div>
      </section>

      <section className="aof-deals">
        <div className="head">
          <h2>Get Best Travel deals</h2>
          <button>Explore more <ArrowRight size={18} /></button>
        </div>
        <div className="cards-wrap">
          <button
            className="nav-btn left"
            onClick={() => setDealsStart((prev) => (prev - 1 + dealCards.length) % dealCards.length)}
            aria-label="Previous deals"
          >
            <ArrowLeft size={20} />
          </button>
          <div className="cards">
          {visibleDeals.map((d) => (
            <article key={d.city} className="deal-card">
              <img src={d.image} alt={d.city} />
              <div className="body">
                <h3>{d.city}</h3>
                <p>{d.duration}</p>
                <p>{d.dates}</p>
                <div>
                <a href={`tel:${dialPhone}`}><Phone size={15} /> Call Us</a>
                </div>
              </div>
            </article>
          ))}
          </div>
          <button
            className="nav-btn right"
            onClick={() => setDealsStart((prev) => (prev + 1) % dealCards.length)}
            aria-label="Next deals"
          >
            <ArrowRight size={20} />
          </button>
        </div>
      </section>

      <section className="aof-grid-four">
        {coreValues.map((v) => (
          <article key={v.title} className="info-card">
            <div className={`icon ${v.tone}`}><v.icon size={22} /></div>
            <h3>{v.title}</h3>
            <p>{v.text}</p>
          </article>
        ))}
      </section>

      <section className="aof-callout">
        <h2>Ready to Book Your Flight?</h2>
        <div className="btns">
          <a href={`tel:${dialPhone}`} className="primary"><Phone size={16} /> Call Now</a>
          <a href={`tel:${dialPhone}`} className="outline">{phone}</a>
        </div>
        <p><Star size={14} fill="currentColor" /> <Star size={14} fill="currentColor" /> <Star size={14} fill="currentColor" /> <Star size={14} fill="currentColor" /> <Star size={14} fill="currentColor" /> 2M+ Happy Customers</p>
      </section>

      <section className="aof-why">
        <h2>Why Choose airtravelofare?</h2>
        <p>Experience the difference with our premium flight booking service</p>
        <div className="aof-grid-four">
          {whyChoose.map((v) => (
            <article key={v.title} className="info-card">
              <div className={`icon ${v.tone}`}><v.icon size={30} /></div>
              <h3>{v.title}</h3>
              <p>{v.text}</p>
            </article>
          ))}
        </div>
      </section>

      <section className="aof-airlines">
        <div className="head">
          <div>
            <h2>Choose from <span>600+</span> Airlines Worldwide</h2>
            <p>Find the perfect airline for your journey with competitive prices and excellent service</p>
          </div>
          <input
            placeholder="Search airlines..."
            value={airlineQuery}
            onChange={(e) => setAirlineQuery(e.target.value)}
          />
        </div>
        <div className="airline-grid">
          {filteredAirlines.map((airline) => (
            <article key={airline.name} className="airline-card" onClick={() => navigate('/airlines')}>
              <div className="logo">
                <img src={airline.logo} alt={airline.name} loading="lazy" />
              </div>
              <h3>{airline.name}</h3>
              <p>Best deals available</p>
            </article>
          ))}
        </div>
      </section>
    </div>
  );
}

export default HomeNew;
